    Lifetime: the bytes a Tensor exposes (Float32s, BFloat16sToF32, …) alias
    the owning SafetensorsFile's mapped region — they are NOT copies. They stay
    valid only while that file is alive and un-Closed. Calling Tensor() after
    Close returns an error; but a tensor (or slice) obtained BEFORE Close and
    read AFTER it dereferences unmapped memory — a crash or silent garbage the
    flag can't catch. Keep the file alive for the whole lifetime of any data
    drawn from it:

        // WRONG — the returned slice outlives the file's mapping.
        func load() []float32 {
            f, _ := embed.OpenSafetensorsMmap("model.safetensors")
            defer f.Close()                 // unmaps on return…
            t, _ := f.Tensor("weight")
            v, _ := t.Float32s()
            return v                        // …v now aliases freed memory
        }

        // RIGHT — copy out, or keep the file alive as long as the data is used.
        func load() []float32 {
            f, _ := embed.OpenSafetensorsMmap("model.safetensors")
            defer f.Close()
            t, _ := f.Tensor("weight")
            v, _ := t.Float32s()
            return append([]float32(nil), v...) // independent copy; safe to outlive f
        }

